import React from 'react';

const Card = ({ children, className, title, action, subtitle, icon: Icon, hover = true }) => {
  return (
    <div className={`group relative bg-white dark:bg-secondary-800 rounded-2xl border border-violet-200 dark:border-violet-700 shadow-xl hover:shadow-2xl transition-all duration-300 ${
      hover ? 'hover:-translate-y-1' : ''
    } ${className || ''}`}>
      {/* Background decoration */}
      <div className="absolute top-0 right-0 w-24 h-24 bg-gradient-to-br opacity-5 rounded-full blur-2xl group-hover:opacity-10 transition-opacity"
        style={{
          background: 'linear-gradient(135deg, #8b5cf6, #6366f1, #ec4899)',
          transform: 'translate(30%, -30%)'
        }}
      />

      {/* Header */}
      {(title || Icon || action) && (
        <div className="flex items-center justify-between p-6 pb-4">
          <div className="flex items-center gap-3">
            {Icon && (
              <div className="w-10 h-10 bg-gradient-to-br from-violet-500 to-purple-600 rounded-xl flex items-center justify-center shadow-md group-hover:scale-110 transition-transform duration-300">
                <Icon className="w-5 h-5 text-white" />
              </div>
            )}
            <div>
              {title && (
                <h3 className="text-lg font-semibold text-secondary-800 dark:text-secondary-200">
                  {title}
                </h3>
              )}
              {subtitle && (
                <p className="text-sm text-secondary-500 dark:text-secondary-400 mt-1">
                  {subtitle}
                </p>
              )}
            </div>
          </div>

          {action && (
            <div className="transform transition-transform duration-200 group-hover:scale-105">
              {action}
            </div>
          )}
        </div>
      )}

      {/* Content */}
      <div className={`${title || Icon || action ? 'px-6 pb-6' : 'p-6'}`}>
        {children}
      </div>
    </div>
  );
};

export default Card;
